class AttentionBackend(ABC):
    """Abstract class for attention backends."""

    supported_dtypes: ClassVar[list[torch.dtype]] = [torch.float16, torch.bfloat16]
    supported_kv_cache_dtypes: ClassVar[list["CacheDType"]] = [
        "auto",
        "float16",
        "bfloat16",
    ]

    # Does attention's forward() include kv cache update?
    forward_includes_kv_cache_update: bool = True

    @staticmethod
    @abstractmethod
    def get_name() -> str:
        raise NotImplementedError

    @staticmethod
    @abstractmethod
    def get_impl_cls() -> type["AttentionImplBase"]:
        raise NotImplementedError

    @staticmethod
    @abstractmethod
    def get_builder_cls():  # -> Type["AttentionMetadataBuilder"]:
        raise NotImplementedError

    @staticmethod
    @abstractmethod
    def get_kv_cache_shape(
        num_blocks: int,
        block_size: int,
        num_kv_heads: int,
        head_size: int,
        cache_dtype_str: str = "auto",
    ) -> tuple[int, ...]:
        raise NotImplementedError

@classmethod
def validate_configuration(
    cls,
    head_size: int,
    dtype: torch.dtype,
    kv_cache_dtype: "CacheDType | None",
    block_size: int | None,
    use_mla: bool,
    has_sink: bool,
    use_sparse: bool,
    use_mm_prefix: bool,
    use_per_head_quant_scales: bool,
    device_capability: "DeviceCapability",
    attn_type: str,
    use_non_causal: bool = False,
    use_batch_invariant: bool = False,
) -> list[str]:
    invalid_reasons = []
    if not cls.supports_head_size(head_size):
        invalid_reasons.append("head_size not supported")
    if not cls.supports_dtype(dtype):
        invalid_reasons.append("dtype not supported")
    if not cls.supports_kv_cache_dtype(kv_cache_dtype):
        invalid_reasons.append("kv_cache_dtype not supported")
    if not cls.supports_block_size(block_size):
        invalid_reasons.append("block_size not supported")
    ...
    if use_mla != cls.is_mla():
        if use_mla:
            invalid_reasons.append("MLA not supported")
        else:
            invalid_reasons.append("non-MLA not supported")
    ...
    if not cls.supports_compute_capability(device_capability):
        invalid_reasons.append("compute capability not supported")
    if not cls.supports_attn_type(attn_type):
        invalid_reasons.append(f"attention type {attn_type} not supported")
    ...
    return invalid_reasons

def get_path(self, include_classname: bool = True) -> str:
    """Get the class path for this backend (respects overrides)."""
    path = _ATTN_OVERRIDES.get(self, self.value)
    if not path:
        raise ValueError(
            f"Backend {self.name} must be registered before use. "
            f"Use register_backend(Backend.{self.name}, 'your.module.YourClass')"
        )
    if not include_classname:
        path = path.rsplit(".", 1)[0]
    return path

def get_class(self) -> "type[AttentionBackend]":
    """Get the backend class (respects overrides)."""
    return resolve_obj_by_qualname(self.get_path())

@classmethod
def get_attn_backend_cls(
    cls,
    selected_backend: AttentionBackendEnum | None,
    attn_selector_config: AttentionSelectorConfig,
    num_heads: int | None = None,
) -> str:
    device_capability = cls.get_device_capability()
    assert device_capability is not None

    # First try checking just the selected backend, if there is one.
    if selected_backend is not None:
        try:
            backend_class = selected_backend.get_class()
            invalid_reasons = backend_class.validate_configuration(
                device_capability=device_capability,
                **attn_selector_config._asdict(),
            )
        except ImportError:
            invalid_reasons = ["ImportError"]
        if invalid_reasons:
            raise ValueError(
                f"Selected backend {selected_backend} is not valid for "
                f"this configuration. Reason: {invalid_reasons}"
            )
        else:
            logger.info("Using %s backend.", selected_backend)
            return selected_backend.get_path()

    # No selected backend or the selected backend is invalid,
    # so we try finding a valid backend.
    valid_backends_priorities, all_invalid_reasons = cls.get_valid_backends(
        device_capability=device_capability,
        attn_selector_config=attn_selector_config,
        num_heads=num_heads,
    )
    ...
    if len(valid_backends_priorities) == 0:
        raise ValueError(...)

    # We have found some valid backends. Select the one with the
    # highest priority.
    sorted_indices = sorted(
        range(len(valid_backends_priorities)),
        key=lambda i: valid_backends_priorities[i][1],
    )
    selected_index = sorted_indices[0]
    selected_backend = valid_backends_priorities[selected_index][0]
    ...
    return selected_backend.get_path()

@staticmethod
def get_impl_cls() -> type["FlashAttentionImpl"]:
    return FlashAttentionImpl

@staticmethod
def get_builder_cls() -> type["FlashAttentionMetadataBuilder"]:
    return FlashAttentionMetadataBuilder

@staticmethod
def get_kv_cache_shape(
    num_blocks: int,
    block_size: int,
    num_kv_heads: int,
    head_size: int,
    cache_dtype_str: str = "auto",
) -> tuple[int, ...]:
    if block_size % 16 != 0:
        raise ValueError("Block size must be a multiple of 16.")
    return (2, num_blocks, block_size, num_kv_heads, head_size)

